<template>
    <div class="q-pa-md" style="max-width: 400px">
  
      <q-form
        @submit="onSubmit"
        @reset="onReset"
        class="q-gutter-md"
      >
      <template v-for="(field,index) in fields">
          <template v-if="field.foreign">
              <ForeignKey :index="index"  :model="field.label" :multiple="Array.isArray(field.value)" @childEvent="onChildEvent" />
          </template>
          <template v-else-if="!default_modeltypes.includes(field.modeltype.toLowerCase())">
              <p>{{ field.label }}</p>
              <ModelCell :props="{src:field.value,index:index,col:field.name}" :component="'Admin'+field.modeltype"  @update="colUpdate"/>
            </template>
          <template v-else-if="imagestypes.includes(field.modeltype.toLowerCase())">
              <!--<Uploader :index="index" auto-upload @upload="onFileChildEvent" />-->
                  <Uploader :index="index" :hide-upload-btn="false" multiple @upload-success="handleUploadSuccess" @upload-error="handleUploadError" @upload=""/>
          </template>
          <template v-else-if="field.modeltype.toLowerCase()=='boolean'">
              <q-checkbox
                  v-model="field.value"
                  :label="field.label"
              />
          </template>
          <template v-else>
              <q-input 
                  filled
                  v-model="field.value"
                  :label="field.label"
              />
          </template>
      </template>
        <div>
          <q-btn label="Submit" type="submit" color="primary"/>
          <q-btn label="Reset" type="reset" color="primary" flat class="q-ml-sm" />
        </div>
      </q-form>
  
    </div>
  </template>
  
