          return {
              uploadTrigger: false,
              imagestypes: ['image','images'],
              default_modeltypes:[
                      "string",
                      "number",
                      "boolean"
                      //"interface"
                  ]
          }
      },
      methods: {
         async upload(){
             this.uploadTrigger=true
             console.log('uploading')
         },
         async onSubmit () {
              console.log('onSubmit')

              for (let i = 0; i < this.fields.length; i++) {
                console.log(this.fields[i].name,this.fields[i].value)
                  if(this.fields[i].value===undefined) continue
                  this.model[this.fields[i].name] = this.fields[i].value
                  console.log(this.model)
              }
              console.log(this.model.toObject())
              var model=this.model.toObject()
             // var payload = {model_name:model.getClassName(),model:model}
              // await this.adminService.createEntity(payload)
              //     .then((response) => {
              //         // $q.notify({
              //         //     color: 'green-4',
              //         //     textColor: 'white',
              //         //     icon: 'cloud_done',
              //         //     message: 'Submitted'
              //         // })
              //     }).catch((error) => {
              //         // $q.notify({
              //         //     color: 'red-5',
              //         //     textColor: 'white',
              //         //     icon: 'warning',
              //         //     message: error
              //         // })
              //     })
              if(this.service.model=="User"){
                  this.adminService.createUser(model).then((response) => {
                      this.onReset()
                      // this.$q.notify({
                      //     color: 'green-4',
                      //     textColor: 'white',
                      //     icon: 'cloud_done',
                      //     message: 'Submitted'
                      // })
                  }).catch((error) => {
                      console.log(error)
                      // this.$q.notify({
                      //     color: 'red-5',
                      //     textColor: 'white',
                      //     icon: 'warning',
                      //     message: error
                      // })
                  })
              }else{
                  this.service.create(model).then((response) => {
                      this.onReset()
                      // this.$q.notify({
                      //     color: 'green-4',
                      //     textColor: 'white',
                      //     icon: 'cloud_done',
                      //     message: 'Submitted'
                      // })
                  }).catch((error) => {
                      console.log(error)
                      // this.$q.notify({
                      //     color: 'red-5',
                      //     textColor: 'white',
                      //     icon: 'warning',
                      //     message: error
                      // })
                  })
              }
              
          },
          onReset () {
              for (let i = 0; i < this.fields.length; i++) {
                  console.log(this.fields[i].value)
                  console.log(typeof this.fields[i].value)
                  if(Array.isArray(this.fields[i].value)){
                      this.fields[i].value = []
                  }else if(typeof this.fields[i].value==='boolean'){
                      this.fields[i].value = false
                  }else{
                      this.fields[i].value = null
                  }
              }
          },
          onChildEvent(data, index) {
            console.log(data)
              this.fields[index].value = data;
          },
          onFileChildEvent(data, index) {
              console.log('onFileChildEvent',data, index)
              this.fields[index].value = data;
             // this.onSubmit()
          },
          handleUploadSuccess (index,url) {
              console.log('handleUploadSuccess',url)
              if(Array.isArray(this.fields[index].value)){
                  this.fields[index].value.push( url)
              }else{
                  this.fields[index].value = url
              }
              //this.onSubmit()
          },
          colUpdate(val){
              console.log('colUpdate',val)
              this.fields= this.fields.map(row => {
                  if(row.key==val.index){
                  row[val.col] = val.value
                  }
                  return row
              })
              }
      },
      created(){
          this.$q = useQuasar()
          // const model = this.model
          // const service = new AdminService(model)
          // service.fields().then((response) => {
          //     this.fields = response.data
